describe('RateLimiter', () => {
  let store: RedisRateLimitStore;
  let limiter: RateLimiter;

  beforeEach(() => {
    const redis = createMockRedis();
    store = new RedisRateLimitStore(redis, 60000, 'test:');
    limiter = new RateLimiter(store, { limit: 5, windowMs: 60000 });
  });

  describe('checkLimit', () => {
    it('should allow requests within limit', async () => {
      const result = await limiter.checkLimit('user:123');
      
      expect(result.allowed).toBe(true);
      expect(result.remaining).toBe(4);
    });

    it('should block requests exceeding limit', async () => {
      // Use up the limit
      for (let i = 0; i < 5; i++) {
        await limiter.checkLimit('user:123');
      }
      
      const result = await limiter.checkLimit('user:123');
      
      expect(result.allowed).toBe(false);
      expect(result.remaining).toBe(0);
      expect(result.retryAfter).toBeDefined();
    });

    it('should track different identifiers separately', async () => {
      // Use up limit for user 1
      for (let i = 0; i < 5; i++) {
        await limiter.checkLimit('user:1');
      }
      
      // User 2 should still have full limit
      const result = await limiter.checkLimit('user:2');
      
      expect(result.allowed).toBe(true);
      expect(result.remaining).toBe(4);
    });
  });

  describe('resetLimit', () => {
    it('should reset limit for identifier', async () => {
      // Use up the limit
      for (let i = 0; i < 5; i++) {
        await limiter.checkLimit('user:123');
      }
      
      await limiter.resetLimit('user:123');
      
      const result = await limiter.checkLimit('user:123');
      expect(result.allowed).toBe(true);
      expect(result.remaining).toBe(4);
    });
  });

  describe('process', () => {
    it('should process request and set headers', async () => {
      const req = createMockRequest();
      const res = createMockResponse();
      
      const result = await limiter.process(req, res);
      
      expect(result.allowed).toBe(true);
      expect(res.setHeader).toHaveBeenCalledWith('X-RateLimit-Limit', 5);
      expect(res.setHeader).toHaveBeenCalledWith('X-RateLimit-Remaining', expect.any(Number));
    });

    it('should return 429 when limit exceeded', async () => {
      const req = createMockRequest();
      const res = createMockResponse();
      
      // Use up the limit
      for (let i = 0; i < 5; i++) {
        await limiter.process(createMockRequest(), createMockResponse());
      }
      
      const result = await limiter.process(req, res);
      
      expect(result.allowed).toBe(false);
      expect(res.status).toHaveBeenCalledWith(429);
      expect(res.json).toHaveBeenCalledWith(expect.objectContaining({
        error: 'Too Many Requests'
      }));
    });

    it('should skip rate limiting when skip function returns true', async () => {
      const customLimiter = new RateLimiter(store, {
        limit: 1,
        windowMs: 60000,
        skip: (req) => req.user?.role === 'admin'
      });
      
      const adminReq = createMockRequest({ user: { id: '1', role: 'admin' } });
      const res = createMockResponse();
      
      // First request
      await customLimiter.process(adminReq, res);
      // Second request should still be allowed because skip returns true
      const result = await customLimiter.process(adminReq, res);
      
      expect(result.allowed).toBe(true);
    });
  });
});

