describe('Rate Limiting Integration', () => {
  it('should handle concurrent requests correctly', async () => {
    const redis = createMockRedis();
    const limiter = createRateLimiter(redis, { limit: 10, windowMs: 60000 });
    
    // Simulate 15 concurrent requests
    const requests = Array(15).fill(null).map(() => 
      limiter.checkLimit('concurrent:test')
    );
    
    const results = await Promise.all(requests);
    const allowed = results.filter(r => r.allowed).length;
    const blocked = results.filter(r => !r.allowed).length;
    
    // At least some should be blocked after limit reached
    expect(blocked).toBeGreaterThan(0);
  });

  it('should handle window expiration', async () => {
    const redis = createMockRedis();
    // Very short window for testing
    const store = new RedisRateLimitStore(redis, 100, 'test:');
    const limiter = new RateLimiter(store, { limit: 2, windowMs: 100 });
    
    // Use up limit
    await limiter.checkLimit('expire:test');
    await limiter.checkLimit('expire:test');
    
    // Should be blocked
    let result = await limiter.checkLimit('expire:test');
    expect(result.allowed).toBe(false);
    
    // Wait for window to expire
    await new Promise(resolve => setTimeout(resolve, 150));
    
    // Should be allowed again
    result = await limiter.checkLimit('expire:test');
    expect(result.allowed).toBe(true);
  }, 10000);
});

