describe('Security', () => {
  it('should not expose sensitive data in logs', async () => {
    const paymentIntent = createPaymentIntent({
      status: 'succeeded',
      // Sensitive data that should not be logged
      client_secret: 'sk_live_123456'
    });
    
    const consoleSpy = vi.spyOn(console, 'log');
    
    const event = createMockStripeEvent('payment_intent.succeeded', paymentIntent);
    
    (prisma.payment.findFirst as any).mockResolvedValue(null);
    
    await processStripeEvent(event);
    
    // Verify client_secret is not in logs
    const logs = consoleSpy.mock.calls.flat().join(' ');
    expect(logs).not.toContain('sk_live');
    expect(logs).not.toContain('client_secret');
    
    consoleSpy.mockRestore();
  });

  it('should validate event types', async () => {
    const event = createMockStripeEvent('unknown.event.type', {});
    
    // Should handle unknown event types gracefully
    await expect(processStripeEvent(event)).resolves.not.toThrow();
  });

  it('should prevent replay attacks via idempotency', async () => {
    const eventId = 'evt_replay_123';
    
    (prisma.webhookEvent.findUnique as any).mockResolvedValueOnce({
      id: 'we_123',
      stripeEventId: eventId,
      processed: true
    });
    
    const isProcessed = await isEventProcessed(eventId);
    
    expect(isProcessed).toBe(true);
  });
});
